theme.custom_css_code:
.candyland-brand-wrap *{box-sizing:border-box}
.candyland-brand-wrap{
  width:100%;
  font-family:Arial,Helvetica,sans-serif;
  color:#ffeaf8;
}
.candyland-brand-card{
  width:100%;
  border:1px solid rgba(255,255,255,.14);
  border-radius:20px;
  overflow:hidden;
  background:rgba(255,255,255,.04);
  backdrop-filter:blur(6px);
}
.candyland-brand-scroll{
  width:100%;
  overflow-x:auto;
}
.candyland-brand-table{
  width:100%;
  min-width:720px;
  border-collapse:collapse;
}
.candyland-brand-table td{
  padding:16px 18px;
  border-bottom:1px solid rgba(255,255,255,.1);
  vertical-align:top;
  font-size:14px;
  line-height:1.5;
}
.candyland-brand-table tr:last-child td{
  border-bottom:none;
}
.candyland-brand-table td:first-child{
  width:240px;
  font-weight:700;
  color:#ffffff;
  background:rgba(255,255,255,.03);
}
.candyland-brand-table td:last-child{
  color:#ffd8f2;
}
.candyland-brand-badge{
  display:inline-block;
  padding:5px 10px;
  border-radius:999px;
  background:rgba(255,255,255,.08);
  border:1px solid rgba(255,255,255,.12);
  font-size:12px;
  font-weight:700;
  letter-spacing:.2px;
}
@media (max-width:767px){
  .candyland-brand-card{
    border-radius:16px;
  }
  .candyland-brand-table td{
    padding:14px 14px;
    font-size:13px;
  }
  .candyland-brand-table td:first-child{
    width:200px;
  }
}
.candyland-games-wrap *{box-sizing:border-box}
.candyland-games-wrap{
  width:100%;
  font-family:Arial,Helvetica,sans-serif;
  color:#fff3fb;
}
.candyland-games-grid{
  display:grid;
  grid-template-columns:repeat(4,minmax(0,1fr));
  gap:16px;
}
.candyland-games-tile{
  position:relative;
  min-height:170px;
  padding:18px;
  border-radius:22px;
  border:1px solid rgba(255,255,255,.14);
  background:linear-gradient(180deg,rgba(255,255,255,.08),rgba(255,255,255,.04));
  overflow:hidden;
}
.candyland-games-tile:before{
  content:"";
  position:absolute;
  right:-24px;
  top:-24px;
  width:86px;
  height:86px;
  border-radius:50%;
  background:radial-gradient(circle,rgba(255,255,255,.18),rgba(255,255,255,0));
}
.candyland-games-icon{
  font-size:30px;
  line-height:1;
  margin-bottom:14px;
}
.candyland-games-title{
  font-size:17px;
  font-weight:700;
  margin:0 0 8px;
  color:#ffffff;
}
.candyland-games-text{
  margin:0;
  font-size:14px;
  line-height:1.55;
  color:#ffd9f1;
}
.candyland-games-meta{
  display:inline-block;
  margin-top:14px;
  padding:6px 10px;
  border-radius:999px;
  border:1px solid rgba(255,255,255,.12);
  background:rgba(255,255,255,.06);
  font-size:12px;
  font-weight:700;
  color:#fff1fa;
}
@media (max-width:991px){
  .candyland-games-grid{
    grid-template-columns:repeat(2,minmax(0,1fr));
  }
}
@media (max-width:600px){
  .candyland-games-grid{
    grid-template-columns:1fr;
  }
  .candyland-games-tile{
    min-height:auto;
    border-radius:18px;
  }
}
.candyland-chart-wrap *{box-sizing:border-box}
.candyland-chart-wrap{
  width:100%;
  font-family:Arial,Helvetica,sans-serif;
  color:#fff2fa;
}
.candyland-chart-card{
  padding:22px 18px 18px;
  border-radius:22px;
  border:1px solid rgba(255,255,255,.14);
  background:linear-gradient(180deg,rgba(255,255,255,.05),rgba(255,255,255,.03));
}
.candyland-chart{
  display:flex;
  align-items:flex-end;
  justify-content:space-between;
  gap:14px;
  min-height:320px;
  padding:20px 10px 10px;
  border-radius:16px;
  background-image:
    linear-gradient(to top, rgba(255,255,255,.08) 1px, transparent 1px);
  background-size:100% 20%;
}
.candyland-chart-col{
  flex:1 1 0;
  display:flex;
  flex-direction:column;
  align-items:center;
  justify-content:flex-end;
  min-width:0;
}
.candyland-chart-bar{
  width:100%;
  max-width:88px;
  min-height:24px;
  border-radius:18px 18px 8px 8px;
  background:linear-gradient(180deg,#ffd8f1 0%, #ff91d0 45%, #ff5fbb 100%);
  box-shadow:0 10px 24px rgba(255,95,187,.2);
  border:1px solid rgba(255,255,255,.18);
  position:relative;
}
.candyland-chart-bar:before{
  content:"";
  position:absolute;
  left:10%;
  right:10%;
  top:8px;
  height:28%;
  border-radius:999px;
  background:rgba(255,255,255,.18);
}
.candyland-chart-value{
  position:absolute;
  top:-34px;
  left:50%;
  transform:translateX(-50%);
  font-size:12px;
  font-weight:700;
  color:#ffffff;
  white-space:nowrap;
}
.candyland-chart-label{
  margin-top:14px;
  text-align:center;
  font-size:13px;
  line-height:1.35;
  color:#ffd6ee;
}
@media (max-width:767px){
  .candyland-chart-card{
    padding:16px 12px 14px;
    border-radius:18px;
  }
  .candyland-chart{
    gap:10px;
    min-height:240px;
    padding:18px 4px 8px;
  }
  .candyland-chart-value{
    font-size:11px;
    top:-28px;
  }
  .candyland-chart-label{
    font-size:11px;
  }
  .candyland-chart-bar{
    max-width:56px;
    border-radius:12px 12px 6px 6px;
  }
}
